/**
 * Generate fake price_observations for demo testing.
 *
 * Fake data is tagged on insert so it can be removed in one query when real
 * fieldwork data lands. Two markers, both used by purge-fake-data.mjs:
 *   • price_observations.source     = 'fake'
 *   • store_skus.verified_by        = 'fake_seed'
 * Plus a softening of the confidence weight (0.50 vs 0.95 for manual) so
 * that, even if real data coexists later, the materialized view's
 * confidence-weighted aggregate prefers real numbers.
 *
 * Prices are generated by Vertex AI Gemini (gemini-2.5-flash), batched per
 * chain. One model call per chain (~10 chains) produces 50–80 prices each.
 * Cost is well under $0.05 for the whole run. Auth via Application Default
 * Credentials — no API key in env.
 *
 * Usage (from repo root):
 *   node web/scripts/generate-fake-prices.mjs              # generate + insert
 *   node web/scripts/generate-fake-prices.mjs --dry-run    # generate only,
 *                                                            print + save JSON
 *   node web/scripts/generate-fake-prices.mjs --replace    # purge existing
 *                                                            fake rows first
 *
 * After insertion the current_prices materialized view is refreshed so the
 * /api/compare endpoint sees the new rows immediately.
 */

import { createHash } from 'crypto'
import { writeFileSync, mkdirSync, existsSync, readFileSync } from 'fs'
import { resolve, dirname, join } from 'path'
import { fileURLToPath } from 'url'

import { VertexAI } from '@google-cloud/vertexai'

import { createClient } from './seed-utils.mjs'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = resolve(__dirname, '..', '..')
const TMP = resolve(ROOT, 'tmp')
// Per-prompt cache so re-runs are free. Mirrors the gpt-cache /
// llm-review-cache pattern used elsewhere — keyed on the SHA-256 of the
// fully-rendered user prompt + cache version.
const CACHE_DIR = resolve(TMP, 'llm-review-cache')

// Bump when the prompt template, model, or output schema changes. Old
// cached responses become unreachable, forcing a fresh model call. Was
// implicit under OpenRouter/Haiku; now explicit for the Vertex AI swap.
const CACHE_VERSION = 2

// ── Args ─────────────────────────────────────────────────────────────────────

const args = process.argv.slice(2)
const DRY_RUN = args.includes('--dry-run')
const REPLACE = args.includes('--replace')

// ── Config ───────────────────────────────────────────────────────────────────

// Which chains to fake. Names must match `chains.name` exactly. Each chain
// gets a curated price-tier hint that gets passed to the model in the prompt
// so generated numbers are plausible relative to each other.
const CHAIN_CONFIG = [
  { name: "Trader Joe's",     tier: 'budget',     loyalty: false, pricing: 'chain_uniform' },
  { name: 'Costco',           tier: 'bulk-budget',loyalty: false, pricing: 'chain_uniform' },
  { name: 'Walmart',          tier: 'budget',     loyalty: false, pricing: 'chain_uniform' },
  { name: 'Grocery Outlet',   tier: 'discount',   loyalty: false, pricing: 'per_store' },
  { name: 'Safeway',          tier: 'mid',        loyalty: true,  pricing: 'regional' },
  { name: 'Target',           tier: 'mid',        loyalty: false, pricing: 'regional' },
  { name: 'Nugget Markets',   tier: 'mid-plus',   loyalty: true,  pricing: 'regional' },
  { name: 'Whole Foods',      tier: 'premium',    loyalty: true,  pricing: 'regional' },
]

const STORES_PER_CHAIN = 3       // how many stores per chain to attach prices to
const CANONICAL_LIMIT = 150      // how many canonicals to price across all chains
const MODEL = 'gemini-2.5-flash'
const LOCATION = process.env.GOOGLE_CLOUD_LOCATION ?? 'us-west1'

// Anchor location for picking nearby stores per chain. Defaults to central
// Davis since that's where the hackathon will run; receipts uploaded from
// elsewhere still see fake prices because the radius is global.
const ANCHOR = { lon: -121.7405, lat: 38.5449 }

// ── Env loader (kept for legacy .env.local usage) ────────────────────────────
//
// Vertex AI uses ADC (run `gcloud auth application-default login` once locally
// or inherit the Cloud Run service account in production). All this loader
// does now is surface vars the createClient() helper might need (PG*,
// SUPABASE_*) when the script is run from a context without them already set.
{
  const envPath = resolve(ROOT, 'web', '.env.local')
  if (existsSync(envPath)) {
    for (const line of readFileSync(envPath, 'utf8').split('\n')) {
      const t = line.trim()
      if (!t || t.startsWith('#')) continue
      const eq = t.indexOf('=')
      if (eq === -1) continue
      const k = t.slice(0, eq).trim()
      const v = t.slice(eq + 1).trim().replace(/^['"]|['"]$/g, '')
      if (!process.env[k]) process.env[k] = v
    }
  }
}

if (!process.env.GOOGLE_CLOUD_PROJECT) {
  console.error('Missing GOOGLE_CLOUD_PROJECT. Set it in web/.env.local or your shell:')
  console.error('  export GOOGLE_CLOUD_PROJECT=aftercart-494521')
  console.error('And ensure Application Default Credentials are configured:')
  console.error('  gcloud auth application-default login')
  process.exit(1)
}

// ── Connect + load DB context ────────────────────────────────────────────────

const db = createClient()
await db.connect()

if (REPLACE && !DRY_RUN) {
  const { rowCount: obsDel } = await db.query(`DELETE FROM price_observations WHERE source = 'fake'`)
  const { rowCount: skuDel } = await db.query(
    `DELETE FROM store_skus
     WHERE verified_by = 'fake_seed'
       AND store_sku_id NOT IN (SELECT store_sku_id FROM price_observations)`,
  )
  console.log(`✓ --replace: removed ${obsDel} fake observations + ${skuDel} unreferenced fake store_skus\n`)
}

// Resolve chain ids (only chains that exist in the DB, ignoring CHAIN_CONFIG entries that don't).
const { rows: chainRows } = await db.query(
  `SELECT chain_id, name FROM chains WHERE name = ANY($1)`,
  [CHAIN_CONFIG.map((c) => c.name)],
)
const chainMap = new Map(chainRows.map((r) => [r.name, r.chain_id]))

// Pick the top N canonicals. Order: original seed first (stable, low ids), then a wide spread
// so we get coverage across categories the test receipts hit.
const { rows: products } = await db.query(
  `SELECT canonical_id, name, package_size, package_unit, pricing_unit, category_id
   FROM canonical_products
   WHERE description_embedding IS NOT NULL
   ORDER BY canonical_id ASC
   LIMIT $1`,
  [CANONICAL_LIMIT],
)
console.log(`Pricing ${products.length} canonicals across ${chainMap.size} chains.`)

// Pick STORES_PER_CHAIN nearest-to-anchor stores for each chain we're faking.
const chainStores = new Map()
for (const cfg of CHAIN_CONFIG) {
  const chainId = chainMap.get(cfg.name)
  if (!chainId) {
    console.warn(`  ⚠ chain "${cfg.name}" not in DB — skipping`)
    continue
  }
  const { rows: stores } = await db.query(
    `SELECT store_id, address,
            ST_Distance(location, ST_SetSRID(ST_MakePoint($2, $3), 4326)::geography) / 1609.344 AS miles
     FROM stores
     WHERE chain_id = $1
     ORDER BY miles ASC
     LIMIT $4`,
    [chainId, ANCHOR.lon, ANCHOR.lat, STORES_PER_CHAIN],
  )
  chainStores.set(cfg.name, { chain_id: chainId, stores })
  console.log(`  ${cfg.name.padEnd(20)} → ${stores.length} stores ($${cfg.tier})`)
}

// ── Vertex AI client (singleton) ─────────────────────────────────────────────

let vertexClient = null
function getVertex() {
  if (!vertexClient) {
    vertexClient = new VertexAI({ project: process.env.GOOGLE_CLOUD_PROJECT, location: LOCATION })
  }
  return vertexClient
}

// JSON shape the model is asked to return — also used as the responseSchema
// to constrain output server-side. Mirrors the prompt instructions below.
const PRICE_SCHEMA = {
  type: 'object',
  properties: {
    prices: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          id: { type: 'integer' },
          shelf_price: { type: 'number' },
          member_price: { type: 'number' },
          display_name: { type: 'string' },
          pack_size: { type: 'number' },
          pack_unit: { type: 'string' },
        },
        required: ['id', 'shelf_price', 'member_price', 'display_name', 'pack_size', 'pack_unit'],
      },
    },
  },
  required: ['prices'],
}

async function callGemini(systemPrompt, userPrompt) {
  const vertex = getVertex()
  const model = vertex.getGenerativeModel({
    model: MODEL,
    systemInstruction: { role: 'system', parts: [{ text: systemPrompt }] },
    generationConfig: {
      responseMimeType: 'application/json',
      responseSchema: PRICE_SCHEMA,
      temperature: 0.4,
    },
  })

  const result = await model.generateContent({
    contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
  })

  const text = result?.response?.candidates?.[0]?.content?.parts
    ?.map((p) => p.text ?? '')
    .filter(Boolean)
    .join('')
  if (!text) throw new Error('Vertex returned empty content')

  // Defense-in-depth: even with responseMimeType=application/json some models
  // still occasionally wrap in markdown fences. Strip and parse.
  const stripped = text
    .replace(/^\s*```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim()
  try { return JSON.parse(stripped) } catch { throw new Error(`Non-JSON: ${stripped.slice(0, 200)}`) }
}

// ── Per-prompt cache ─────────────────────────────────────────────────────────

function sha256(s) {
  return createHash('sha256').update(s).digest('hex')
}
function cachePath(key) {
  return join(CACHE_DIR, `${key}-v${CACHE_VERSION}.json`)
}
function readCache(key) {
  const f = cachePath(key)
  if (!existsSync(f)) return null
  try { return JSON.parse(readFileSync(f, 'utf8')) } catch { return null }
}
function writeCache(key, data) {
  mkdirSync(CACHE_DIR, { recursive: true })
  writeFileSync(cachePath(key), JSON.stringify(data, null, 2))
}

const SYSTEM_PROMPT = `You generate realistic 2026 California grocery shelf prices for testing.

Return ONLY valid JSON (no markdown fences) in this exact shape:
{
  "prices": [
    { "id": 1, "shelf_price": 4.59, "member_price": 4.59, "display_name": "Lucerne Whole Milk, 1 gal", "pack_size": 128, "pack_unit": "fl_oz" },
    { "id": 2, "shelf_price": 3.99, "member_price": 3.79, "display_name": "Signature SELECT Eggs, Large, 12 ct", "pack_size": 12, "pack_unit": "count" }
  ]
}

Each "id" matches the integer ID of the item in the input. Return one entry per input item; do not skip or add items.

display_name is what THIS chain typically prints on shelves and receipts — including the chain's house brand AND the pack size. Examples:
- Safeway whole milk → "Lucerne Whole Milk, 1 gal"
- Whole Foods whole milk → "365 Organic Whole Milk, 1 gal"
- Trader Joe's whole milk → "Trader Joe's Whole Milk, 1 gal"
- Costco whole milk → "Kirkland Signature Whole Milk, 2 × 1 gal"
- Walmart whole milk → "Great Value Whole Milk, 1 gal"
- Target whole milk → "Good & Gather Whole Milk, 1 gal"
- Nugget Markets whole milk → "Clover Sonoma Organic Whole Milk, 1 gal"
- Grocery Outlet → use the actual national brand likely to be on the shelf (e.g. "Horizon Organic Whole Milk, 1 gal") since Grocery Outlet doesn't have a house brand
For non-house-brand items, use the dominant national brand for that chain's clientele. Always include the pack size.

pack_size and pack_unit: the numeric size and unit of the product THIS chain sells. This is critical — different chains sell different sizes of the same product. Examples:
- Costco peanut butter: pack_size=48, pack_unit="oz"
- Safeway peanut butter: pack_size=16, pack_unit="oz"
- Costco milk (2-pack): pack_size=256, pack_unit="fl_oz" (total volume)
- TJ's dark chocolate: pack_size=3.5, pack_unit="oz"
- Eggs 12ct: pack_size=12, pack_unit="count"
- By-weight items (chicken thighs sold per lb): pack_size=1, pack_unit="lb"
Valid units: oz, lb, fl_oz, gal, ml, l, g, kg, count, each

Pricing tiers (relative to a typical mid-tier grocery store):
- "budget" / "discount": 10-25% below average
- "bulk-budget" (Costco): 15-30% below per-unit on staples
- "mid": baseline
- "mid-plus": 5-15% above
- "premium" (Whole Foods): 20-40% above

Loyalty rules:
- If chain has loyalty: member_price is 5-20% below shelf_price on roughly 1 in 4 items, equal otherwise.
- If no loyalty: member_price MUST equal shelf_price exactly.

Use realistic 2026 California pricing.`

function buildUserPrompt(chainCfg, items) {
  const itemList = items.map((p, i) => {
    const size = p.package_size != null && p.package_unit ? ` ${p.package_size} ${p.package_unit}` : ''
    return `id=${i + 1}: ${p.name}${size} — sold ${p.pricing_unit}`
  }).join('\n')

  return `Store: ${chainCfg.name}
Tier: ${chainCfg.tier}
Loyalty program: ${chainCfg.loyalty ? 'yes' : 'no'}

Items:
${itemList}

Return JSON with one price per item id (ids 1..${items.length}).`
}

const generated = {}  // chain_name → [{ id, shelf_price, member_price, display_name }]
console.log('\nGenerating prices…')

for (const cfg of CHAIN_CONFIG) {
  if (!chainStores.has(cfg.name)) continue
  process.stdout.write(`  ${cfg.name.padEnd(20)} `)
  const userPrompt = buildUserPrompt(cfg, products)
  const cacheKey = sha256(`${MODEL}::${SYSTEM_PROMPT}::${userPrompt}`)
  try {
    let out = readCache(cacheKey)
    let cached = !!out
    if (!out) {
      out = await callGemini(SYSTEM_PROMPT, userPrompt)
      writeCache(cacheKey, out)
    }
    if (!Array.isArray(out.prices)) {
      throw new Error(`response missing prices array (got ${typeof out.prices})`)
    }
    generated[cfg.name] = out.prices
    process.stdout.write(`${out.prices.length} prices ✓${cached ? ' (cached)' : ''}\n`)
  } catch (err) {
    process.stdout.write(`failed: ${err.message}\n`)
  }
}

// Write a JSON snapshot to tmp/ for audit.
mkdirSync(TMP, { recursive: true })
const snapshotPath = join(TMP, `fake-prices-${new Date().toISOString().replace(/[:.]/g, '-')}.json`)
writeFileSync(snapshotPath, JSON.stringify(generated, null, 2))
console.log(`\nSnapshot: ${snapshotPath}`)

if (DRY_RUN) {
  console.log('\n--dry-run: stopping before DB writes.')
  await db.end()
  process.exit(0)
}

// ── Insert into DB ───────────────────────────────────────────────────────────

let totalSkus = 0
let totalObs = 0
const issues = []

for (const cfg of CHAIN_CONFIG) {
  const stores = chainStores.get(cfg.name)
  const prices = generated[cfg.name]
  if (!stores || !prices) continue

  for (const priceRow of prices) {
    // Items were sent with id=1..N; look up by 1-indexed position.
    const idx = Number(priceRow.id) - 1
    const product = idx >= 0 && idx < products.length ? products[idx] : null
    if (!product) {
      issues.push(`${cfg.name}: bad id ${priceRow.id}`)
      continue
    }
    const shelf = Number(priceRow.shelf_price)
    const member = Number(priceRow.member_price ?? shelf)
    if (!Number.isFinite(shelf) || shelf <= 0) {
      issues.push(`${cfg.name}/${product.name}: bad shelf_price ${priceRow.shelf_price}`)
      continue
    }

    // display_name is what the chain prints on shelves/receipts (model-generated,
    // chain-specific). Falls back to the canonical name if the model omitted it.
    const displayName =
      typeof priceRow.display_name === 'string' && priceRow.display_name.trim().length > 0
        ? priceRow.display_name.trim()
        : product.name

    // Structured pack size from the LLM response; fall back to canonical.
    const packSize = Number(priceRow.pack_size) > 0 ? Number(priceRow.pack_size) : (product.package_size ?? null)
    const packUnit = typeof priceRow.pack_unit === 'string' && priceRow.pack_unit.trim()
      ? priceRow.pack_unit.trim()
      : (product.package_unit ?? null)

    // Find or create the chain-wide store_sku, tagged so the purger knows.
    // receipt_text_canonical stays as the canonical name (the lookup key for
    // matching) — display_name carries the chain-specific shelf label.
    const skuRes = await db.query(
      `WITH ins AS (
         INSERT INTO store_skus
           (chain_id, store_id, canonical_id, receipt_text_canonical,
            display_name, pack_size, pack_unit,
            status, confidence, verified_at, verified_by)
         VALUES ($1, NULL, $2, $3, $4, $5, $6, 'verified', 0.50, NOW(), 'fake_seed')
         ON CONFLICT (chain_id, receipt_text_canonical) DO UPDATE
           SET display_name = EXCLUDED.display_name,
               pack_size = EXCLUDED.pack_size,
               pack_unit = EXCLUDED.pack_unit
           WHERE store_skus.verified_by = 'fake_seed'
         RETURNING store_sku_id
       )
       SELECT store_sku_id FROM ins
       UNION ALL
       SELECT store_sku_id FROM store_skus
       WHERE chain_id = $1 AND receipt_text_canonical = $3
       LIMIT 1`,
      [stores.chain_id, product.canonical_id, product.name, displayName, packSize, packUnit],
    )
    const storeSkuId = skuRes.rows[0]?.store_sku_id
    if (!storeSkuId) {
      issues.push(`${cfg.name}/${product.name}: failed to resolve store_sku`)
      continue
    }
    totalSkus++

    // Attach the price to each near-anchor store, with ±2% per-store wobble
    // so the comparison UI shows distinct numbers per store rather than
    // identical values across N rows. Wobble is deterministic per store_id
    // so re-runs of the loader produce stable values.
    for (const s of stores.stores) {
      const wobble = ((Number(s.store_id) % 11) - 5) * 0.004  // ~±2%
      const obsShelf = Math.max(0.01, shelf * (1 + wobble))
      const obsMember = Math.max(0.01, member * (1 + wobble))

      // shelf-tier observation (always)
      await db.query(
        `INSERT INTO price_observations
           (store_sku_id, canonical_id, store_id, chain_id,
            price_total, quantity, quantity_unit,
            price_per_unit, price_unit,
            observed_at, source, pricing_tier, confidence)
         VALUES
           ($1, $2, $3, $4,
            $5, 1, $6,
            $5, $7,
            NOW(), 'fake', 'shelf', 0.50)`,
        [
          storeSkuId, product.canonical_id, s.store_id, stores.chain_id,
          Number(obsShelf.toFixed(2)), product.package_unit, product.pricing_unit,
        ],
      )
      totalObs++

      // member-tier observation only when loyalty applies AND the model
      // returned a discounted price. Avoids cluttering the view with
      // duplicate rows for stores that don't actually have a member tier.
      if (cfg.loyalty && obsMember < obsShelf - 0.01) {
        await db.query(
          `INSERT INTO price_observations
             (store_sku_id, canonical_id, store_id, chain_id,
              price_total, quantity, quantity_unit,
              price_per_unit, price_unit,
              observed_at, source, pricing_tier, confidence)
           VALUES
             ($1, $2, $3, $4,
              $5, 1, $6,
              $5, $7,
              NOW(), 'fake', 'member', 0.50)`,
          [
            storeSkuId, product.canonical_id, s.store_id, stores.chain_id,
            Number(obsMember.toFixed(2)), product.package_unit, product.pricing_unit,
          ],
        )
        totalObs++
      }
    }
  }
}

console.log(`\nRefreshing current_prices…`)
try { await db.query(`REFRESH MATERIALIZED VIEW CONCURRENTLY current_prices`) }
catch { await db.query(`REFRESH MATERIALIZED VIEW current_prices`) }
console.log('✓ Refreshed.')

await db.end()

console.log('\nSummary:')
console.log(`  Chains priced:                ${Object.keys(generated).length}`)
console.log(`  Store SKUs touched:           ${totalSkus}`)
console.log(`  Price observations inserted:  ${totalObs}`)
if (issues.length > 0) {
  console.log(`\n${issues.length} issues:`)
  for (const m of issues.slice(0, 20)) console.log(`  • ${m}`)
  if (issues.length > 20) console.log(`  ... ${issues.length - 20} more`)
}
console.log('\nFake data is tagged source=\'fake\' / verified_by=\'fake_seed\'.')
console.log('Wipe with: node web/scripts/purge-fake-data.mjs')
